/**
 * Line-diff `old` against `new` (word-level inline emphasis on modified
 * lines), highlighting both sides with `language_hint`. Rows come back in
 * document order with 1-based line numbers on each side.
 */
public func diffHighlighted(old: String, new: String, languageHint: String) -> [DiffRow]  {
    return try!  FfiConverterSequenceTypeDiffRow.lift(try! rustCall() {
        uniffiCallStatus in
    uniffi_tesseract_highlight_fn_func_diff_highlighted(
        FfiConverterString.lower(old),
        FfiConverterString.lower(new),
        FfiConverterString.lower(languageHint),uniffiCallStatus
    )
})
}
/**
 * Highlight `code` line by line. `language_hint` is a fence token ("swift"),
 * an extension ("rs"), or a file path ("Sources/Foo.swift"); unknown hints
 * fall back to plain text (single Plain span per line).
 */
public func highlight(code: String, languageHint: String) -> [HighlightedLine]  {
    return try!  FfiConverterSequenceTypeHighlightedLine.lift(try! rustCall() {
        uniffiCallStatus in
    uniffi_tesseract_highlight_fn_func_highlight(
        FfiConverterString.lower(code),
        FfiConverterString.lower(languageHint),uniffiCallStatus
    )
})
}

private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_tesseract_highlight_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_tesseract_highlight_checksum_func_diff_highlighted() != 4289) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tesseract_highlight_checksum_func_highlight() != 34250) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

// Make the ensure init function public so that other modules which have external type references to
// our types can call it.
public func uniffiEnsureTesseractHighlightInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

